  1→import { existsSync, mkdirSync, unlinkSync, writeFileSync, readFileSync } from "node:fs";
  2→import { join } from "node:path";
  3→import { randomBytes, createHash } from "node:crypto";
  4→import { findGitRoot, saveRepoConfig, loadGlobalConfig } from "../config";
  5→import { BrainHttpClient } from "../http-client";
  6→import {
  7→  BRAIN_HOOKS,
  8→  BRAIN_CLAUDE_MD,
  9→  BRAIN_COMMANDS,
 10→} from "./init-content";
 11→
 12→const DEFAULT_SERVER_URL = "http://localhost:3000";
 13→
 14→export async function runInit(): Promise<void> {
 15→  const serverUrl = process.env.BRAIN_SERVER_URL ?? DEFAULT_SERVER_URL;
 16→  const workspaceId = process.env.BRAIN_WORKSPACE_ID;
 17→
 18→  const gitRoot = findGitRoot(process.cwd());
 19→  if (!gitRoot) {
 20→    console.error("Not inside a git repository. Run brain init from a project directory.");
 21→    process.exit(1);
 22→  }
 23→
 24→  if (!workspaceId) {
 25→    console.error("Set BRAIN_WORKSPACE_ID env var to your workspace ID.");
 26→    console.error("Find it in the Brain web UI or the database.");
 27→    process.exit(1);
 28→  }
 29→
 30→  console.log("Brain Init\n──────────\n");
 31→
 32→  // Step 1: Auth
 33→  await setupAuth(serverUrl, workspaceId, gitRoot);
 34→
 35→  // Step 2: .mcp.json
 36→  await setupMcpJson(gitRoot);
 37→
 38→  // Step 3: .claude/settings.json hooks
 39→  await setupClaudeHooks(gitRoot);
 40→
 41→  // Step 4: CLAUDE.md
 42→  await setupClaudeMd(gitRoot);
 43→
 44→  // Step 5: Commands
 45→  await setupCommands(gitRoot);
 46→
 47→  // Step 6: Git hooks
 48→  installGitHooks(gitRoot);
 49→
 50→  console.log(`\nDone. Restart Claude Code to activate.`);
 51→}
 52→
 53→// ---------------------------------------------------------------------------
 54→// Step 1: Auth (OAuth 2.1 PKCE)
 55→// ---------------------------------------------------------------------------
 56→
 57→const DEFAULT_SCOPES = "graph:read graph:reason decision:write task:write observation:write question:write session:write offline_access";
 58→
 59→function base64url(buf: Buffer): string {
 60→  return buf.toString("base64url");
 61→}
 62→
 63→function generatePkce(): { verifier: string; challenge: string } {
 64→  const verifier = base64url(randomBytes(32));
 65→  const challenge = base64url(createHash("sha256").update(verifier).digest());
 66→  return { verifier, challenge };
 67→}
 68→
 69→export async function setupAuth(
 70→  serverUrl: string,
 71→  workspaceId: string,
 72→  gitRoot: string,
 73→  options?: { openUrl?: (url: string) => void },
 74→): Promise<void> {
 75→  const global = await loadGlobalConfig();
 76→  const existing = global?.repos[gitRoot];
 77→  if (existing && existing.workspace === workspaceId && existing.access_token) {
 78→    console.log(`✓ Auth: already configured for ${gitRoot}`);
 79→    return;
 80→  }
 81→
 82→  // 1. Verify workspace exists
 83→  try {
 84→    await BrainHttpClient.listProjects(serverUrl, workspaceId);
 85→  } catch {
 86→    console.error(`Workspace ${workspaceId} not found on ${serverUrl}`);
 87→    process.exit(1);
 88→  }
 89→
 90→  // 2. Dynamic Client Registration
 91→  const dcrRes = await fetch(`${serverUrl}/api/auth/oauth2/register`, {
 92→    method: "POST",
 93→    headers: { "Content-Type": "application/json" },
 94→    body: JSON.stringify({
 95→      client_name: `brain-cli-${workspaceId.slice(0, 8)}`,
 96→      redirect_uris: ["http://127.0.0.1/callback"],
 97→      grant_types: ["authorization_code", "refresh_token"],
 98→      response_types: ["code"],
 99→      token_endpoint_auth_method: "none",
100→    }),
101→  });
102→  if (!dcrRes.ok) {
103→    throw new Error(`Client registration failed: ${dcrRes.status} ${await dcrRes.text()}`);
104→  }
105→  const { client_id } = await dcrRes.json() as { client_id: string };
106→
107→  // 3. PKCE
108→  const pkce = generatePkce();
109→  const state = base64url(randomBytes(16));
110→
111→  // 4. Start local callback server
112→  const { promise: codePromise, resolve: resolveCode, reject: rejectCode } = Promise.withResolvers<string>();
113→
114→  const callbackServer = Bun.serve({
115→    port: 0,
116→    hostname: "127.0.0.1",
117→    routes: {
118→      "/callback": (request) => {
119→        const url = new URL(request.url);
120→        const code = url.searchParams.get("code");
121→        const returnedState = url.searchParams.get("state");
122→        const error = url.searchParams.get("error");
123→
124→        if (error) {
125→          rejectCode(new Error(`OAuth error: ${error}`));
126→          return new Response("<html><body><h1>Authentication failed</h1><p>You can close this tab.</p></body></html>", {
127→            headers: { "Content-Type": "text/html" },
128→          });
129→        }
130→        if (returnedState !== state) {
131→          rejectCode(new Error("state mismatch"));
132→          return new Response("<html><body><h1>State mismatch</h1></body></html>", {
133→            headers: { "Content-Type": "text/html" },
134→          });
135→        }
136→        if (!code) {
137→          rejectCode(new Error("no code returned"));
138→          return new Response("<html><body><h1>No authorization code</h1></body></html>", {
139→            headers: { "Content-Type": "text/html" },
140→          });
141→        }
142→
143→        resolveCode(code);
144→        return new Response("<html><body><h1>Authenticated!</h1><p>You can close this tab and return to the terminal.</p></body></html>", {
145→          headers: { "Content-Type": "text/html" },
146→        });
147→      },
148→    },
149→  });
150→
151→  const redirectUri = `http://127.0.0.1:${callbackServer.port}/callback`;
152→
153→  // Update redirect_uris with actual port (re-register)
154→  const dcrUpdateRes = await fetch(`${serverUrl}/api/auth/oauth2/register`, {
155→    method: "POST",
156→    headers: { "Content-Type": "application/json" },
157→    body: JSON.stringify({
158→      client_name: `brain-cli-${workspaceId.slice(0, 8)}`,
159→      redirect_uris: [redirectUri],
160→      grant_types: ["authorization_code", "refresh_token"],
161→      response_types: ["code"],
162→      token_endpoint_auth_method: "none",
163→    }),
164→  });
165→  if (!dcrUpdateRes.ok) {
166→    callbackServer.stop();
167→    throw new Error(`Client re-registration failed: ${dcrUpdateRes.status} ${await dcrUpdateRes.text()}`);
168→  }
169→  const dcrUpdate = await dcrUpdateRes.json() as { client_id: string };
170→  const actualClientId = dcrUpdate.client_id;
171→
172→  // 5. Open browser
173→  const authUrl = new URL(`${serverUrl}/api/auth/oauth2/authorize`);
174→  authUrl.searchParams.set("client_id", actualClientId);
175→  authUrl.searchParams.set("redirect_uri", redirectUri);
176→  authUrl.searchParams.set("response_type", "code");
177→  authUrl.searchParams.set("scope", DEFAULT_SCOPES);
178→  authUrl.searchParams.set("code_challenge", pkce.challenge);
179→  authUrl.searchParams.set("code_challenge_method", "S256");
180→  authUrl.searchParams.set("state", state);
181→  // Pass resource so better-auth issues a JWT access token (not opaque)
182→  authUrl.searchParams.set("resource", serverUrl);
183→
184→  console.log("Opening browser for authentication...");
185→  console.log(`If the browser doesn't open, visit: ${authUrl.toString()}\n`);
186→
187→  const openUrl = options?.openUrl ?? ((url: string) => {
188→    const openCmd = process.platform === "darwin" ? "open" : process.platform === "win32" ? "start" : "xdg-open";
189→    Bun.spawn([openCmd, url], { stdout: "ignore", stderr: "ignore" });
190→  });
191→  openUrl(authUrl.toString());
192→
193→  // 6. Wait for callback
194→  let code: string;
195→  try {
196→    code = await codePromise;
197→  } catch (error) {
198→    callbackServer.stop();
199→    throw error;
200→  }
201→
202→  // 7. Exchange code for tokens
203→  const tokenRes = await fetch(`${serverUrl}/api/auth/oauth2/token`, {
204→    method: "POST",
205→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
206→    body: new URLSearchParams({
207→      grant_type: "authorization_code",
208→      code,
209→      redirect_uri: redirectUri,
210→      client_id: actualClientId,
211→      code_verifier: pkce.verifier,
212→      resource: serverUrl,
213→    }),
214→  });
215→
216→  callbackServer.stop();
217→
218→  if (!tokenRes.ok) {
219→    throw new Error(`Token exchange failed: ${tokenRes.status} ${await tokenRes.text()}`);
220→  }
221→
222→  const tokens = await tokenRes.json() as {
223→    access_token: string;
224→    refresh_token: string;
225→    expires_in: number;
226→    token_type: string;
227→  };
228→
229→  // 8. Store tokens
230→  await saveRepoConfig(serverUrl, gitRoot, {
231→    workspace: workspaceId,
232→    client_id: actualClientId,
233→    access_token: tokens.access_token,
234→    refresh_token: tokens.refresh_token,
235→    token_expires_at: Math.floor(Date.now() / 1000) + tokens.expires_in,
236→  });
237→
238→  console.log(`✓ Auth: OAuth tokens saved for ${gitRoot}`);
239→}
240→
241→// ---------------------------------------------------------------------------
242→// Step 2: .mcp.json
243→// ---------------------------------------------------------------------------
244→
245→export async function setupMcpJson(gitRoot: string): Promise<void> {
246→  const mcpPath = join(gitRoot, ".mcp.json");
247→  const file = Bun.file(mcpPath);
248→  let mcp: { mcpServers: Record<string, unknown> } = { mcpServers: {} };
249→
250→  if (await file.exists()) {
251→    try {
252→      mcp = await file.json();
253→      mcp.mcpServers ??= {};
254→    } catch {
255→      // Corrupted file — overwrite
256→    }
257→  }
258→
259→  mcp.mcpServers.brain = { command: "brain", args: ["mcp"] };
260→  await Bun.write(mcpPath, JSON.stringify(mcp, null, 2) + "\n");
261→  console.log("✓ MCP: .mcp.json updated");
262→}
263→
264→// ---------------------------------------------------------------------------
265→// Step 3: .claude/settings.json hooks
266→// ---------------------------------------------------------------------------
267→
268→type HookEntry = { type: string; command?: string; prompt?: string };
269→type SettingsHookGroup = { matcher?: string; hooks: HookEntry[] };
270→
271→export async function setupClaudeHooks(gitRoot: string): Promise<void> {
272→  const claudeDir = join(gitRoot, ".claude");
273→  if (!existsSync(claudeDir)) mkdirSync(claudeDir, { recursive: true });
274→
275→  const settingsPath = join(claudeDir, "settings.json");
276→  const file = Bun.file(settingsPath);
277→  let settings: Record<string, unknown> = {};
278→
279→  if (await file.exists()) {
280→    try {
281→      settings = await file.json();
282→    } catch {
283→      // Corrupted — start fresh
284→    }
285→  }
286→
287→  const hooks = (settings.hooks ?? {}) as Record<string, SettingsHookGroup[]>;
288→  let added = 0;
289→
290→  for (const [event, hookDefs] of Object.entries(BRAIN_HOOKS)) {
291→    hooks[event] ??= [];
292→
293→    const hasBrain = hooks[event].some((group) =>
294→      group.hooks?.some(
295→        (h) => h.command?.startsWith("brain ") || h.prompt?.includes("Brain MCP"),
296→      ),
297→    );
298→
299→    if (!hasBrain) {
300→      hooks[event].push({ hooks: hookDefs as HookEntry[] });
301→      added++;
302→    }
303→  }
304→
305→  settings.hooks = hooks;
306→  await Bun.write(settingsPath, JSON.stringify(settings, null, 2) + "\n");
307→  console.log(`✓ Hooks: .claude/settings.json updated (${added} hooks added)`);
308→}
309→
310→// ---------------------------------------------------------------------------
311→// Step 4: CLAUDE.md
312→// ---------------------------------------------------------------------------
313→
314→export const MARKER_START = "<!-- brain-plugin-start -->";
315→export const MARKER_END = "<!-- brain-plugin-end -->";
316→
317→export async function setupClaudeMd(gitRoot: string): Promise<void> {
318→  const claudeMdPath = join(gitRoot, "CLAUDE.md");
319→  const file = Bun.file(claudeMdPath);
320→  let content = "";
321→
322→  if (await file.exists()) {
323→    content = await file.text();
324→  }
325→
326→  const brainBlock = `${MARKER_START}\n${BRAIN_CLAUDE_MD}\n${MARKER_END}`;
327→
328→  const startIdx = content.indexOf(MARKER_START);
329→  const endIdx = content.indexOf(MARKER_END);
330→
331→  if (startIdx !== -1 && endIdx !== -1) {
332→    content = content.slice(0, startIdx) + brainBlock + content.slice(endIdx + MARKER_END.length);
333→  } else {
334→    const separator = content.length > 0 && !content.endsWith("\n\n") ? "\n\n" : "";
335→    content = content + separator + brainBlock + "\n";
336→  }
337→
338→  await Bun.write(claudeMdPath, content);
339→  console.log("✓ CLAUDE.md: Brain plugin instructions added");
340→}
341→
342→// ---------------------------------------------------------------------------
343→// Step 6: Git hooks
344→// ---------------------------------------------------------------------------
345→
346→export function installGitHooks(gitRoot?: string): void {
347→  const root = gitRoot ?? findGitRoot(process.cwd());
348→  if (!root) {
349→    console.log("  No .git directory found — skipping git hook installation.");
350→    return;
351→  }
352→
353→  const hooksDir = join(root, ".git", "hooks");
354→  if (!existsSync(hooksDir)) mkdirSync(hooksDir, { recursive: true });
355→
356→  const preCommitPath = join(hooksDir, "pre-commit");
357→  const postCommitPath = join(hooksDir, "post-commit");
358→  const preCommitScript = `#!/bin/sh
359→# Brain pre-commit hook: check for task completion and unlogged decisions
360→brain check-commit
361→`;
362→
363→  if (!existsSync(preCommitPath)) {
364→    writeFileSync(preCommitPath, preCommitScript, { mode: 0o755 });
365→    console.log("✓ Git: pre-commit hook installed");
366→  } else {
367→    console.log("✓ Git: pre-commit hook already exists");
368→  }
369→
370→  // Remove legacy Brain post-commit hook
371→  if (existsSync(postCommitPath)) {
372→    const postCommitContent = readFileSync(postCommitPath, "utf-8");
373→    const isBrainManaged =
374→      postCommitContent.includes("Brain post-commit hook") &&
375→      postCommitContent.includes("brain log-commit");
376→    if (isBrainManaged) {
377→      unlinkSync(postCommitPath);
378→      console.log("  Removed legacy Brain post-commit hook");
379→    }
380→  }
381→}
382→
383→export async function setupCommands(gitRoot: string): Promise<void> {
384→  const commandsDir = join(gitRoot, ".claude", "commands");
385→  if (!existsSync(commandsDir)) mkdirSync(commandsDir, { recursive: true });
386→
387→  let count = 0;
388→  for (const [filename, content] of Object.entries(BRAIN_COMMANDS)) {
389→    await Bun.write(join(commandsDir, filename), content + "\n");
390→    count++;
391→  }
392→
393→  console.log(`✓ Commands: ${count} slash commands installed to .claude/commands/`);
394→}
