  1→import { useState, useEffect } from "react";
  2→import { useSearch } from "@tanstack/react-router";
  3→import { useSession } from "../lib/auth-client";
  4→import { getScopeDescription } from "../../shared/scopes";
  5→
  6→type ClientInfo = { client_name: string };
  7→
  8→export function ConsentPage() {
  9→  const { data: session, isPending: sessionPending } = useSession();
 10→  const search = useSearch({ strict: false }) as Record<string, string>;
 11→
 12→  const [clientName, setClientName] = useState<string>();
 13→  const [loading, setLoading] = useState(false);
 14→  const [error, setError] = useState("");
 15→
 16→  const clientId = search.client_id;
 17→  const scopeString = search.scope ?? "";
 18→  const scopes = scopeString.split(" ").filter(Boolean);
 19→
 20→  // Fetch client name for display
 21→  useEffect(() => {
 22→    if (!clientId) return;
 23→    fetch(`/api/auth/oauth-client/${encodeURIComponent(clientId)}`)
 24→      .then((res) => (res.ok ? res.json() : undefined))
 25→      .then((data: ClientInfo | undefined) => {
 26→        if (data?.client_name) setClientName(data.client_name);
 27→      })
 28→      .catch(() => {});
 29→  }, [clientId]);
 30→
 31→  // Redirect to sign-in if not authenticated
 32→  if (!sessionPending && !session) {
 33→    const params = new URLSearchParams(search);
 34→    window.location.href = `/sign-in?redirectTo=${encodeURIComponent(`/consent?${params.toString()}`)}`;
 35→    return undefined;
 36→  }
 37→
 38→  async function handleConsent(accept: boolean) {
 39→    setLoading(true);
 40→    setError("");
 41→
 42→    try {
 43→      const res = await fetch("/api/auth/oauth2/consent", {
 44→        method: "POST",
 45→        headers: { "Content-Type": "application/json" },
 46→        body: JSON.stringify({
 47→          accept,
 48→          ...(accept ? { scope: scopeString } : {}),
 49→        }),
 50→      });
 51→
 52→      const data = await res.json() as { url?: string; redirect?: boolean };
 53→
 54→      if (data.url) {
 55→        window.location.href = data.url;
 56→        return;
 57→      }
 58→
 59→      setError("Unexpected response from authorization server");
 60→    } catch (err) {
 61→      setError(err instanceof Error ? err.message : "Consent request failed");
 62→    } finally {
 63→      setLoading(false);
 64→    }
 65→  }
 66→
 67→  if (sessionPending) {
 68→    return (
 69→      <div className="consent-page">
 70→        <div className="consent-card">
 71→          <p className="consent-loading">Loading...</p>
 72→        </div>
 73→      </div>
 74→    );
 75→  }
 76→
 77→  return (
 78→    <div className="consent-page">
 79→      <div className="consent-card">
 80→        <h1 className="consent-title">Authorize Application</h1>
 81→
 82→        <p className="consent-client">
 83→          <strong>{clientName ?? clientId ?? "An application"}</strong> is requesting access to your account.
 84→        </p>
 85→
 86→        {session?.user && (
 87→          <p className="consent-user">
 88→            Signed in as <strong>{session.user.email ?? session.user.name}</strong>
 89→          </p>
 90→        )}
 91→
 92→        {scopes.length > 0 && (
 93→          <div className="consent-scopes">
 94→            <p className="consent-scopes-label">This will allow the application to:</p>
 95→            <ul className="consent-scope-list">
 96→              {scopes.map((scope) => (
 97→                <li key={scope} className="consent-scope-item">
 98→                  <span className="consent-scope-desc">{getScopeDescription(scope)}</span>
 99→                  <span className="consent-scope-name">{scope}</span>
100→                </li>
101→              ))}
102→            </ul>
103→          </div>
104→        )}
105→
106→        {error && <p className="consent-error">{error}</p>}
107→
108→        <div className="consent-actions">
109→          <button
110→            type="button"
111→            className="consent-button consent-allow"
112→            onClick={() => handleConsent(true)}
113→            disabled={loading}
114→          >
115→            {loading ? "..." : "Allow"}
116→          </button>
117→          <button
118→            type="button"
119→            className="consent-button consent-deny"
120→            onClick={() => handleConsent(false)}
121→            disabled={loading}
122→          >
123→            Deny
124→          </button>
125→        </div>
126→      </div>
127→    </div>
128→  );
129→}
