 13→/** Sign up a test user and return session headers for OAuth flow */
 14→async function signUpAndGetSession(baseUrl: string, email: string, name: string): Promise<{
 15→  userId: string;
 16→  headers: Record<string, string>;
 17→}> {
 18→  const res = await fetch(`${baseUrl}/api/auth/sign-up/email`, {
 19→    method: "POST",
 20→    headers: { "Content-Type": "application/json" },
 21→    body: JSON.stringify({ email, password: "test-password-123!", name }),
 22→  });
 23→  if (!res.ok) throw new Error(`Sign up failed: ${res.status} ${await res.text()}`);
 24→
 25→  const data = (await res.json()) as { user: { id: string }; token: string };
 26→  const cookies = res.headers.getSetCookie();
 27→  const sessionCookie = cookies.find((c) => c.startsWith("better-auth.session_token="));
 28→  const sessionToken = sessionCookie
 29→    ? decodeURIComponent(sessionCookie.split("=")[1].split(";")[0])
 30→    : data.token;
 31→
 32→  return {
 33→    userId: data.user.id,
 34→    headers: { Cookie: `better-auth.session_token=${sessionToken}` },
 35→  };
 36→}
