 38→describe("CLI init setupAuth", () => {
 39→  let configDir: string;
 40→  let gitRoot: string;
 41→  const originalConfigDir = process.env.BRAIN_CONFIG_DIR;
 42→
 43→  afterAll(() => {
 44→    // Restore env so other tests aren't affected
 45→    if (originalConfigDir) {
 46→      process.env.BRAIN_CONFIG_DIR = originalConfigDir;
 47→    } else {
 48→      delete process.env.BRAIN_CONFIG_DIR;
 49→    }
 50→    if (configDir) rmSync(configDir, { recursive: true, force: true });
 51→    if (gitRoot) rmSync(gitRoot, { recursive: true, force: true });
 52→  });
 53→
 54→  it("completes full OAuth PKCE flow and saves tokens", async () => {
 55→    const { baseUrl, surreal } = getRuntime();
 56→
 57→    // 1. Create workspace with required SCHEMAFULL fields
 58→    const workspaceId = crypto.randomUUID();
 59→    const wsRecord = new RecordId("workspace", workspaceId);
 60→    await surreal.query(
 61→      `CREATE $ws CONTENT {
 62→        name: "CLI Init Test Workspace",
 63→        status: "active",
 64→        onboarding_complete: true,
 65→        onboarding_turn_count: 0,
 66→        onboarding_summary_pending: false,
 67→        onboarding_started_at: time::now(),
 68→        created_at: time::now()
 69→      };`,
 70→      { ws: wsRecord },
 71→    );
 72→
 73→    // Create a project (listProjects needs at least one)
 74→    const projRecord = new RecordId("project", crypto.randomUUID());
 75→    await surreal.query(
 76→      `CREATE $proj CONTENT {
 77→        name: "Test Project",
 78→        status: "active",
 79→        workspace: $ws,
 80→        created_at: time::now()
 81→      };`,
 82→      { proj: projRecord, ws: wsRecord },
 83→    );
 84→    await surreal.query(`RELATE $ws->has_project->$proj SET added_at = time::now();`, {
 85→      ws: wsRecord,
 86→      proj: projRecord,
 87→    });
 88→
 89→    // 2. Sign up user and create workspace membership
 90→    const { userId, headers: sessionHeaders } = await signUpAndGetSession(
 91→      baseUrl,
 92→      "cli-init-test@example.com",
 93→      "CLI Init Tester",
 94→    );
 95→    const personRecord = new RecordId("person", userId);
 96→    await surreal.query(`RELATE $person->member_of->$ws SET role = "admin", added_at = time::now();`, {
 97→      person: personRecord,
 98→      ws: wsRecord,
 99→    });
100→
101→    // Trigger JWKS key generation
102→    await fetch(`${baseUrl}/api/auth/jwks`);
103→
104→    // 3. Set up temp git repo and isolated config dir
105→    gitRoot = mkdtempSync(join(tmpdir(), "brain-init-auth-"));
106→    execSync("git init", { cwd: gitRoot, stdio: "ignore" });
107→
108→    configDir = mkdtempSync(join(tmpdir(), "brain-init-config-"));
109→    process.env.BRAIN_CONFIG_DIR = configDir;
110→
111→    // 4. Run setupAuth with injectable openUrl that simulates the browser
112→    await setupAuth(baseUrl, workspaceId, gitRoot, {
113→      openUrl: (url: string) => {
114→        // Fire-and-forget async: programmatically complete the OAuth dance
115→        (async () => {
116→          try {
117→            // Parse the auth URL to extract client_id for skipConsent
118→            const authUrl = new URL(url);
119→            const clientId = authUrl.searchParams.get("client_id")!;
120→
121→            // Skip consent screen in test
122→            await surreal.query(`UPDATE oauthClient SET skipConsent = true WHERE clientId = $cid;`, {
123→              cid: clientId,
124→            });
125→
126→            // Sign in again to get fresh session (signup session may have expired)
127→            const signInRes = await fetch(`${baseUrl}/api/auth/sign-in/email`, {
128→              method: "POST",
129→              headers: { "Content-Type": "application/json" },
130→              body: JSON.stringify({ email: "cli-init-test@example.com", password: "test-password-123!" }),
131→            });
132→            const signInData = (await signInRes.json()) as { token: string };
133→            const cookies = signInRes.headers.getSetCookie();
134→            const sessionCookie = cookies.find((c) => c.startsWith("better-auth.session_token="));
135→            const token = sessionCookie
136→              ? decodeURIComponent(sessionCookie.split("=")[1].split(";")[0])
137→              : signInData.token;
138→
139→            // Hit the authorize endpoint — server redirects to the callback URL with the code
140→            const authRes = await fetch(url, {
141→              headers: { Cookie: `better-auth.session_token=${token}` },
142→              redirect: "manual",
143→            });
144→
145→            if (authRes.status !== 302) {
146→              throw new Error(`Authorize did not redirect: ${authRes.status}`);
147→            }
148→
149→            // Follow the redirect to setupAuth's local callback server
150→            const location = authRes.headers.get("location")!;
151→            await fetch(location);
152→          } catch (err) {
153→            console.error("openUrl simulation failed:", err);
154→          }
155→        })();
156→      },
157→    });
158→
159→    // 5. Verify config was saved
160→    const configPath = join(configDir, "config.json");
161→    const config = JSON.parse(readFileSync(configPath, "utf-8")) as BrainGlobalConfig;
162→
163→    expect(config.server_url).toBe(baseUrl);
164→    expect(config.repos[gitRoot]).toBeDefined();
165→
166→    const repo = config.repos[gitRoot];
167→    expect(repo.workspace).toBe(workspaceId);
168→    expect(repo.client_id).toBeTruthy();
169→    expect(repo.access_token).toBeTruthy();
170→    expect(repo.refresh_token).toBeTruthy();
171→    expect(repo.token_expires_at).toBeGreaterThan(Math.floor(Date.now() / 1000));
172→
173→    // 6. Verify the access token actually works on an MCP route
174→    const mcpRes = await fetch(`${baseUrl}/api/mcp/${workspaceId}/projects`, {
175→      headers: { Authorization: `Bearer ${repo.access_token}` },
176→    });
177→    expect(mcpRes.status).toBe(200);
178→  }, 60_000);
