122→              break;
123→            case "gte":
124→              expr = `${w.field} >= $${paramKey}`;
125→              break;
126→            case "lt":
127→              expr = `${w.field} < $${paramKey}`;
128→              break;
129→            case "lte":
130→              expr = `${w.field} <= $${paramKey}`;
131→              break;
132→            case "in":
133→              expr = `${w.field} IN $${paramKey}`;
134→              break;
135→            case "not_in":
136→              expr = `${w.field} NOT IN $${paramKey}`;
137→              break;
138→            case "contains":
139→              expr = `${w.field} CONTAINS $${paramKey}`;
140→              break;
141→            case "starts_with":
142→              expr = `string::starts_with(${w.field}, $${paramKey})`;
143→              break;
144→            case "ends_with":
145→              expr = `string::ends_with(${w.field}, $${paramKey})`;
146→              break;
